{"file_text": "<nav aria-label="Product pagination">
    <ul class="pagination justify-content-center mb-0">
        <li class="page-item @(Page <= 1 ? "disabled" : "")">
            <button class="page-link" @onclick="() => GoToPage(Page - 1)" disabled="@(Page <= 1)">Previous</button>
        </li>
        @for (int i = 1; i <= TotalPages; i++)
        {
            var pageNum = i;
            <li class="page-item @(pageNum == Page ? "active" : "")">
                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
            </li>
        }
        <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
            <button class="page-link" @onclick="() => GoToPage(Page + 1)" disabled="@(Page >= TotalPages)">Next</button>
        </li>
    </ul>
</nav>

@code {
    [Parameter] public int Page { get; set; } = 1;
    [Parameter] public int TotalPages { get; set; } = 1;
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
