@page "/catalog"
@using sv_e5d0e5cb50e94478b1d22552342b6b32.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-3 col-md-4 mb-3">
            <div class="border rounded">
                <CatalogFilters Categories="_categories"
                                OnApply="HandleFiltersApplied"
                                OnClear="HandleFiltersCleared" />
            </div>
        </div>

        <div class="col-lg-9 col-md-8">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 200px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center text-muted py-5">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters or clearing them to see all products.</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_result.TotalCount"
                                Page="_result.Page"
                                PageSize="_pageSize"
                                OnSortChanged="HandleSortChanged" />

                <div class="mt-3">
                    <ProductGrid Products="_result.Items"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                </div>

                @if (TotalPages > 1)
                {
                    <div class="mt-3">
                        <CatalogPagination Page="_result.Page"
                                           TotalPages="TotalPages"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </div>
    </div>
}

@code {
    /// <summary>
    /// Raised when a product card is clicked, allowing a parent to navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private const int _pageSize = 12;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _pageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var categoriesTask = _categories.Count == 0
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);

            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _page, _pageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new(null, null, null, false);
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder — integrate with a cart service
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

